ee:message.ee:set-payload:
%dw 2.0
output application/json
var n = vars.route
var ttp = n.features[0].geometry.coordinates
var sttp = sizeOf(ttp)
var points = vars.pay.points
var pointsInterval = (sttp-1)/(points-1)
var indicesToPick = (0 to (points-2)) map (
	floor($*pointsInterval)
)
var finalIndices = indicesToPick + (sttp - 1)
---
{
	"pointCoordinates" : finalIndices map (
		ttp[$]
	)
}
